	langs := []discovery.LanguageInfo{
		{Name: "go", Adapter: "go"},
		{Name: "typescript", Adapter: "ts"},
		{Name: "python", Adapter: "generic"},
	}
	adapters := discovery.DetectedAdapters(langs)
	if len(adapters) != 3 {
		t.Errorf("adapters = %d, want 3", len(adapters))
	}
