import "fmt"

// Tier represents the analysis capability level for a programming language.
type Tier int

const (
	TierNone    Tier = iota // 0 – no analysis possible
	TierGeneric             // basic/generic analysis only
	TierLint                // lint-level analysis
	TierParse               // parse/ AST-level analysis
	TierFull                // full semantic analysis
)

var tierNames = map[Tier]string{
	TierNone:    "None",
	TierGeneric: "Generic",
	TierLint:    "Lint",
	TierParse:   "Parse",
	TierFull:    "Full",
}

// String returns a human-readable name for the tier.
func (t Tier) String() string {
	if name, ok := tierNames[t]; ok {
		return name
	}
	return fmt.Sprintf("Tier(%d)", int(t))
}

