// When you add a new language to the discovery package, you MUST also add an
// entry here — otherwise TierForLanguage will default to TierGeneric.
var languageTiers = map[string]Tier{
	"go":     TierFull,
	"ts":     TierFull,
	"js":     TierFull,
	"py":     TierFull,
	"rs":     TierFull,
	"rb":     TierGeneric,
	"java":   TierGeneric,
	"kt":     TierGeneric,
	"sh":     TierGeneric,
	"c":      TierGeneric,
	"cpp":    TierGeneric,
	"cs":     TierGeneric,
	"swift":  TierGeneric,
